external_knowledge:
; Movie ratings are subjective and can come from various sources, each potentially using different scales or criteria; 
; The popularity of a movie can be inferred through its presence in watchlists and viewing history; 
; A hierarchical genre structure suggests that genres can have sub-genres, allowing for more specific categorization of movies; 
; Reviews from users can provide insights into the quality or appeal of a movie, often reflected in the average rating.

sql:
SELECT COUNT(movie_id) AS total_movies_in_watchlist
FROM watchlist
WHERE user_id = 0;

SELECT movie_id
FROM watchlist
WHERE added_date = '2023-01-01';

SELECT user_id, COUNT(movie_id) AS number_of_movies_in_watchlist
FROM watchlist
GROUP BY user_id;
